	private static final class SnapshotSibling implements NativeLmdbQuerySource.ParallelSource {
		private final PreflightFailureSource owner;
		private final boolean producer;
		private int closeCalls;
		private boolean closed;

		private SnapshotSibling(PreflightFailureSource owner, boolean producer) {
			this.owner = owner;
			this.producer = producer;
		}

		@Override
		public long idOf(Value value) {
			return owner.idOf(value);
		}

		@Override
		public Value lazyValue(long id) {
			return owner.lazyValue(id);
		}

		@Override
		public Object idSpace() {
			return owner.idSpace;
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) {
			return owner.iteratorFor(subj, pred, producer);
		}

		@Override
		public NativeProbe newProbe() {
			if (!producer) {
				throw new AssertionError("preflight probes must belong to the producer snapshot");
			}
			int attempt = owner.producerProbeCreationAttempts++;
			if (attempt == 0 && owner.firstProbeCreationFailure != null) {
				if (owner.firstProbeCreationFailure instanceof RuntimeException) {
					throw (RuntimeException) owner.firstProbeCreationFailure;
				}
				throw (Error) owner.firstProbeCreationFailure;
			}
			if (attempt == 1 && owner.secondProbeCreationFailure != null) {
				throw owner.secondProbeCreationFailure;
			}
			int probeIndex = owner.producerProbesCreated++;
			return new TrackingProbe(this, owner, probeIndex);
		}

		@Override
		public long count(long subj, long pred, long obj, long context) {
			return 0L;
		}

		@Override
		public boolean has(long subj, long pred, long obj, long context) {
			return owner.has(subj, pred, obj, context);
		}

		@Override
		public double estimate(long subj, long pred, long obj, long context) {
			return 1D;
		}

		@Override
		public boolean hasStatementsInSource() {
			return true;
		}

		@Override
		public void close() {
			if (!closed) {
				closed = true;
				closeCalls++;
			}
		}
	}

	private static final class TrackingProbe implements NativeLmdbQuerySource.NativeProbe {
		private final SnapshotSibling source;
		private final PreflightFailureSource owner;
		private final int index;
		private RecordIterator current;
		private boolean closed;

		private TrackingProbe(SnapshotSibling source, PreflightFailureSource owner, int index) {
			this.source = source;
			this.owner = owner;
			this.index = index;
		}

		@Override
		public RecordIterator open(long subj, long pred, long obj, long context) {
			if (current != null) {
				current.close();
			}
			owner.producerProbeOpenCalls[index]++;
			current = source.statements(subj, pred, obj, context);
			return current;
		}

		@Override
		public void close() {
			if (!closed) {
				closed = true;
				if (current != null) {
					current.close();
					current = null;
				}
				owner.producerProbeCloseCalls[index]++;
				RuntimeException closeFailure = owner.probeCloseFailures[index];
				if (closeFailure != null) {
					throw closeFailure;
				}
			}
		}
	}

	private static final class OneRowIterator implements RecordIterator {
		private final long[] row;
		private final Runnable onClose;
		private int remaining;
		private boolean closed;

		private OneRowIterator(long[] row, Runnable onClose) {
			this(row, 1, onClose);
		}

		private OneRowIterator(long[] row, int rows, Runnable onClose) {
			this.row = row;
			this.remaining = row == null ? 0 : rows;
			this.onClose = onClose;
		}

		@Override
		public long[] next() {
			if (remaining == 0) {
				return null;
			}
			remaining--;
			return row;
		}

		@Override
		public void close() {
			if (!closed) {
				closed = true;
				onClose.run();
			}
		}
	}
